/**
 * Generate GeoJSON for ferry routes + shipping lanes overlay.
 */
export function ferryRoutesGeoJSON() {
  const features = [
    // Ferry routes
    ...ferryRoutes.map(route => ({
      type: 'Feature' as const,
      geometry: {
        type: 'LineString' as const,
        coordinates: route.coordinates,
      },
      properties: {
        name: route.name,
        operator: route.operator,
        speedKts: route.speedKts,
        frequency: route.frequency,
        type: 'ferry',
        color: '#ef4444', // danger-red — ferries are hazardous to small craft
        opacity: 0.6,
        lineWidth: 2,
        dashArray: [4, 4],
      },
    })),
    // Shipping lanes
    ...shippingLanes.map(lane => ({
      type: 'Feature' as const,
      geometry: {
        type: 'LineString' as const,
        coordinates: lane.coordinates,
      },
      properties: {
        name: lane.name,
        operator: 'Commercial shipping',
        description: lane.description,
        speedKts: 14,
        frequency: 'Continuous',
        type: 'shipping',
        color: lane.color,
        opacity: 0.45,
        lineWidth: 8,
        dashArray: [0, 0],
      },
    })),
  ];

  return {
    type: 'FeatureCollection' as const,
    features,
  };
}

/**
 * Back-compat alias — the original file exported `shippingChannel`
 * as the Oakland lane. Preserve that export so nothing breaks.
 */
export const shippingChannel = shippingLanes[0].coordinates;
